{
  "family": "Retro-Claisen Reaction",
  "candidate": {
    "substrate_smiles": [
      "CCC(=O)C(C)C(=O)OCC"
    ],
    "product_smiles": [
      "CCC(=O)C",
      "CCOC(=O)C"
    ],
    "optional_reagent_smiles": [
      "[OH-].[Na+]",
      "O"
    ],
    "rationale": "This example shows the base-catalyzed cleavage of ethyl 2-methyl-3-oxopentanoate, a simple acyclic beta-keto ester. The reaction proceeds via nucleophilic attack of hydroxide at the ketone carbonyl, followed by C-C bond cleavage to yield the enolate of butan-2-one and ethyl acetate. This is a classic textbook illustration of the retro-Claisen reaction, demonstrating the characteristic cleavage of a 1,3-dicarbonyl system into two simpler carbonyl compounds.",
    "collision_avoidance_note": "The chosen substrate is a simple, acyclic beta-keto ester with minimal functional groups to avoid overlap with other named reactions. It avoids aromatic rings, complex stereochemistry, or other reactive motifs that could trigger unrelated reaction families. The products are simple, common ketones and esters, clearly illustrating the cleavage nature of the reaction without ambiguity."
  }
}
